import React, { createContext, useState, useContext, ReactNode } from 'react';

interface AdminUser {
  username: string;
  role: string;
  loginTime: Date;
}

interface AuthContextType {
  user: AdminUser | null;
  login: (username: string, password: string) => boolean;
  logout: () => void;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

interface AuthProviderProps {
  children: ReactNode;
}

export const AuthProvider: React.FC<AuthProviderProps> = ({ children }) => {
  const [user, setUser] = useState<AdminUser | null>(null);

  const login = (username: string, password: string): boolean => {
    console.log('Login attempt:', { username, password: '***' });

    // Check default admin credentials
    if (username === 'ryadav' && password === 'yadav@123') {
      console.log('Default admin credentials matched');
      const newUser: AdminUser = {
        username,
        role: 'admin',
        loginTime: new Date()
      };
      setUser(newUser);
      localStorage.setItem('adminUser', JSON.stringify(newUser));
      console.log('User logged in successfully');
      return true;
    }

    // Check other admin profiles from localStorage
    const adminProfiles = JSON.parse(localStorage.getItem('adminProfiles') || '[]');
    const admin = adminProfiles.find((admin: any) => admin.username === username && admin.password === password);

    if (admin) {
      const newUser: AdminUser = {
        username: admin.username,
        role: admin.role || 'admin',
        loginTime: new Date()
      };
      setUser(newUser);
      localStorage.setItem('adminUser', JSON.stringify(newUser));
      return true;
    }

    console.log('Login failed - invalid credentials');
    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('adminUser');
  };

  const isAuthenticated = !!user;

  // Check for existing session on mount
  React.useEffect(() => {
    const savedUser = localStorage.getItem('adminUser');
    if (savedUser) {
      try {
        const parsedUser = JSON.parse(savedUser);
        setUser(parsedUser);
      } catch (error) {
        console.error('Error parsing saved user:', error);
        localStorage.removeItem('adminUser');
      }
    }
  }, []);

  return (
    <AuthContext.Provider value={{ user, login, logout, isAuthenticated }}>
      {children}
    </AuthContext.Provider>
  );
};
